        ${url ? `<button onclick="shareUrl('${url}')">🔗 Share URL</button>` : ''}
        ${url ? `<button onclick="showQR('${url}', '${p.title}')">📱 QR Code</button>` : ''}
      </div>
    `;
    }).join('');

    document.getElementById('pasteList').innerHTML = html || '<p>No pastes yet</p>';
  };
