// Share URL
function shareUrl(url) {
  if (navigator.share) {
    navigator.share({ url, title: 'Kant Pastebin' });
  } else {
    navigator.clipboard.writeText(url);
    alert('✅ URL copied to clipboard');
  }
}

// Show QR Code
function showQR(url, title) {
  const qrDiv = document.createElement('div');
  qrDiv.style.cssText = 'position:fixed;top:50%;left:50%;transform:translate(-50%,-50%);background:#fff;padding:20px;border:3px solid #0f0;z-index:1000';
  qrDiv.innerHTML = `
    <h3 style="color:#000">${title}</h3>
    <canvas id="qrcode"></canvas>
    <br><button onclick="this.parentElement.remove()">Close</button>
  `;
  document.body.appendChild(qrDiv);

  // Generate QR code
  generateQR(url, document.getElementById('qrcode'));
}

// Simple QR Code generator
function generateQR(text, canvas) {
  const size = 256;
  const qr = qrcode(0, 'M');
  qr.addData(text);
  qr.make();

  const ctx = canvas.getContext('2d');
  const cells = qr.getModuleCount();
  const cellSize = size / cells;

  canvas.width = size;
  canvas.height = size;

  ctx.fillStyle = '#fff';
  ctx.fillRect(0, 0, size, size);
  ctx.fillStyle = '#000';

  for (let row = 0; row < cells; row++) {
    for (let col = 0; col < cells; col++) {
      if (qr.isDark(row, col)) {
        ctx.fillRect(col * cellSize, row * cellSize, cellSize, cellSize);
      }
    }
  }
}

