// Share URL
function shareUrl(url) {
  // Create RDFa-encoded URL with paste metadata
  const tx = db.transaction([STORE_NAME], 'readonly');
  const pasteId = url.split('/').pop();

  tx.objectStore(STORE_NAME).openCursor().onsuccess = (e) => {
    const cursor = e.target.result;
    if (cursor) {
      const p = cursor.value;
      if (p.serverId === pasteId) {
        // Build RDFa URL with metadata
        const rdfaUrl = `${url}#typeof=schema:CreativeWork&property=schema:name=${encodeURIComponent(p.title)}&property=schema:keywords=${encodeURIComponent(p.keywords.join(','))}&property=schema:identifier=${encodeURIComponent(p.ipfsCid || p.cid)}`;

        if (navigator.share) {
          navigator.share({ 
            url: rdfaUrl, 
            title: p.title,
            text: `${p.title} - Kant Pastebin`
          });
        } else {
          navigator.clipboard.writeText(rdfaUrl);
          alert('✅ RDFa URL copied to clipboard:\n\n' + rdfaUrl);
        }
        return;
      }
      cursor.continue();
    }
  };
}

