// Share URL
function shareUrl(url) {
  // Encode entire paste content in URL
  const tx = db.transaction([STORE_NAME], 'readonly');
  const pasteId = url.split('/').pop();

  tx.objectStore(STORE_NAME).openCursor().onsuccess = (e) => {
    const cursor = e.target.result;
    if (cursor) {
      const p = cursor.value;
      if (p.serverId === pasteId) {
        // Compress and encode entire paste in URL fragment
        const data = {
          title: p.title,
          content: p.content,
          keywords: p.keywords,
          timestamp: p.timestamp,
          ipfs_cid: p.ipfsCid
        };
        const encoded = btoa(encodeURIComponent(JSON.stringify(data)));
        const dataUrl = `${window.location.origin}${window.location.pathname}#paste=${encoded}`;

        if (navigator.share) {
          navigator.share({ 
            url: dataUrl, 
            title: p.title,
            text: `${p.title} - Kant Pastebin`
          });
        } else {
          navigator.clipboard.writeText(dataUrl);
          alert('✅ Data URL copied (entire paste in URL):\n\n' + dataUrl.substring(0, 100) + '...');
        }
        return;
      }
      cursor.continue();
    }
